@SpringBootApplication
public class SamlSpApplication {

    public static void main(String[] args) {
        SpringApplication.run(SamlSpApplication.class, args);
    }

    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http, SamlSessionAuthenticationFilter samlSessionAuthenticationFilter) throws Exception {
        http
                .csrf(csrf -> csrf.ignoringRequestMatchers(
                        new AntPathRequestMatcher("/saml/acs", "POST"),
                        new AntPathRequestMatcher("/saml/acs", "GET")
                ))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/saml/**", "/health", "/error").permitAll()
                        .anyRequest().authenticated()
                )
                .addFilterBefore(samlSessionAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
                .httpBasic(Customizer.withDefaults())
                .formLogin(Customizer.withDefaults());
        return http.build();
    }

    @Bean
    AuthenticationManager authenticationManager() {
        return new ProviderManager(Collections.singletonList(authentication -> {
            if (authentication instanceof SamlAuthenticationToken token && token.isAuthenticated()) {
                return token;
            }
            throw new RuntimeException("Unsupported authentication");
        }));
    }
}

@RestController
class SamlAcsController {

    private final SamlResponseProcessor processor;

    SamlAcsController(SamlResponseProcessor processor) {
        this.processor = processor;
    }

    @PostMapping(path = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<Void> acsPost(@RequestParam("SAMLResponse") String samlResponse,
                                        @RequestParam(value = "RelayState", required = false) String relayState,
                                        HttpServletRequest request) {
        processor.processAndCreateSession(request, samlResponse, relayState, SamlBinding.HTTP_POST);
        String redirectTo = processor.resolveRelayState(relayState);
        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.LOCATION, redirectTo);
        return new ResponseEntity<>(headers, HttpStatus.FOUND);
    }

    @GetMapping(path = "/saml/acs")
    public ResponseEntity<Void> acsRedirect(@RequestParam("SAMLResponse") String samlResponse,
                                           @RequestParam(value = "RelayState", required = false) String relayState,
                                           HttpServletRequest request) {
        processor.processAndCreateSession(request, samlResponse, relayState, SamlBinding.HTTP_REDIRECT);
        String redirectTo = processor.resolveRelayState(relayState);
        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.LOCATION, redirectTo);
        return new ResponseEntity<>(headers, HttpStatus.FOUND);
    }

    @GetMapping("/health")
    public Map<String, Object> health() {
        return Map.of("status", "UP", "time", Instant.now().toString());
    }
}

