@Component
class SamlResponseProcessor {

    public static final String SESSION_SAML_ATTRIBUTES = "SAML_ATTRIBUTES";
    public static final String SESSION_SAML_NAMEID = "SAML_NAMEID";
    public static final String SESSION_SAML_SESSION_INDEX = "SAML_SESSION_INDEX";
    public static final String SESSION_SAML_NOT_ON_OR_AFTER = "SAML_NOT_ON_OR_AFTER";
    public static final String SESSION_SAML_ISSUER = "SAML_ISSUER";

    private static final String DEFAULT_RELAYSTATE_TARGET = "/";

    public void processAndCreateSession(HttpServletRequest request, String samlResponseParam, String relayState, SamlBinding binding) {
        if (!StringUtils.hasText(samlResponseParam)) {
            throw new SamlProcessingException("Missing SAMLResponse");
        }

        byte[] decoded = Base64Utils.decodeFromString(samlResponseParam);
        byte[] xmlBytes;
        if (binding == SamlBinding.HTTP_REDIRECT) {
            xmlBytes = inflateRaw(decoded);
        } else {
            xmlBytes = decoded;
        }

        SamlParsedResponse parsed = parseSamlResponse(xmlBytes);

        HttpSession session = request.getSession(true);
        session.setAttribute(SESSION_SAML_ATTRIBUTES, parsed.attributes());
        session.setAttribute(SESSION_SAML_NAMEID, parsed.nameId());
        session.setAttribute(SESSION_SAML_SESSION_INDEX, parsed.sessionIndex());
        session.setAttribute(SESSION_SAML_NOT_ON_OR_AFTER, parsed.notOnOrAfterEpochSeconds());
        session.setAttribute(SESSION_SAML_ISSUER, parsed.issuer());

        List<GrantedAuthority> authorities = deriveAuthorities(parsed.attributes());
        SamlAuthenticationToken auth = new SamlAuthenticationToken(parsed.nameId(), authorities, parsed.attributes());
        auth.setAuthenticated(true);

        SecurityContext context = SecurityContextHolder.createEmptyContext();
        context.setAuthentication(auth);
        SecurityContextHolder.setContext(context);
        session.setAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY, context);
    }

    public String resolveRelayState(String relayState) {
        if (!StringUtils.hasText(relayState)) return DEFAULT_RELAYSTATE_TARGET;
        String rs = relayState.trim();
        if (rs.startsWith("http://") || rs.startsWith("https://")) return rs;
        if (!rs.startsWith("/")) rs = "/" + rs;
        return rs;
    }

    private List<GrantedAuthority> deriveAuthorities(Map<String, List<String>> attributes) {
        List<GrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        List<String> roles = firstNonEmpty(attributes, "roles", "role", "Role", "Roles", "groups", "Group", "Groups");
        if (roles != null) {
            for (String r : roles) {
                if (!StringUtils.hasText(r)) continue;
                String role = r.trim();
                if (role.startsWith("ROLE_")) authorities.add(new SimpleGrantedAuthority(role));
                else authorities.add(new SimpleGrantedAuthority("ROLE_" + role.replace(' ', '_').toUpperCase(Locale.ROOT)));
            }
        }
        return authorities;
    }

    private List<String> firstNonEmpty(Map<String, List<String>> attrs, String... keys) {
        for (String k : keys) {
            List<String> v = attrs.get(k);
            if (v != null && !v.isEmpty()) return v;
        }
        return null;
    }

    private byte[] inflateRaw(byte[] deflated) {
        try (InflaterInputStream in = new InflaterInputStream(new ByteArrayInputStream(deflated), new Inflater(true))) {
            return in.readAllBytes();
        } catch (IOException e) {
            throw new SamlProcessingException("Failed to inflate SAMLResponse (Redirect binding)", e);
        }
    }

    private SamlParsedResponse parseSamlResponse(byte[] xmlBytes) {
        Document doc = parseXmlSecure(xmlBytes);

        String issuer = xpathString(doc, "/*[local-name()='Response']/*[local-name()='Issuer']/text()");
        String statusCode = xpathString(doc, "/*[local-name()='Response']/*[local-name()='Status']/*[local-name()='StatusCode']/@Value");
        if (StringUtils.hasText(statusCode) && !statusCode.endsWith(":Success") && !statusCode.equals("urn:oasis:names:tc:SAML:2.0:status:Success")) {
            String msg = xpathString(doc, "/*[local-name()='Response']/*[local-name()='Status']/*[local-name()='StatusMessage']/text()");
            throw new SamlProcessingException("SAML Status not Success: " + statusCode + (StringUtils.hasText(msg) ? (" (" + msg + ")") : ""));
        }

        String nameId = xpathString(doc,
                "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='Subject']/*[local-name()='NameID']/text()");
        if (!StringUtils.hasText(nameId)) {
            nameId = xpathString(doc,
                    "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='Subject']/*[local-name()='EncryptedID']/*[local-name()='EncryptedData']/*[local-name()='CipherData']/*[local-name()='CipherValue']/text()");
        }
        if (!StringUtils.hasText(nameId)) {
            throw new SamlProcessingException("Missing NameID in Assertion");
        }

        String sessionIndex = xpathString(doc,
                "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='AuthnStatement']/@SessionIndex");

        String notOnOrAfter = xpathString(doc,
                "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='Conditions']/@NotOnOrAfter");
        Long notOnOrAfterEpoch = null;
        if (StringUtils.hasText(notOnOrAfter)) {
            try {
                notOnOrAfterEpoch = Instant.parse(notOnOrAfter).getEpochSecond();
            } catch (Exception ignored) {
            }
        }

        Map<String, List<String>> attributes = extractAttributes(doc);

        return new SamlParsedResponse(issuer, nameId.trim(), sessionIndex, notOnOrAfterEpoch, attributes);
    }

    private Map<String, List<String>> extractAttributes(Document doc) {
        Map<String, List<String>> attrs = new LinkedHashMap<>();

        NodeList attributeNodes = xpathNodeList(doc,
                "/*[local-name()='Response']/*[local-name()='Assertion']" +
                        "/*[local-name()='AttributeStatement']/*[local-name()='Attribute']");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node n = attributeNodes.item(i);
            if (!(n instanceof Element attrEl)) continue;

            String name = attrEl.getAttribute("Name");
            String friendly = attrEl.getAttribute("FriendlyName");
            String key = StringUtils.hasText(friendly) ? friendly : name;
            if (!StringUtils.hasText(key)) continue;

            List<String> values = new ArrayList<>();
            NodeList valueNodes = attrEl.getElementsByTagNameNS("*", "AttributeValue");
            for (int j = 0; j < valueNodes.getLength(); j++) {
                Node v = valueNodes.item(j);
                String text = v != null ? v.getTextContent() : null;
                if (text != null) {
                    String t = text.trim();
                    if (StringUtils.hasText(t)) values.add(t);
                }
            }

            if (!values.isEmpty()) {
                attrs.computeIfAbsent(key, k -> new ArrayList<>()).addAll(values);
                if (StringUtils.hasText(name) && !name.equals(key)) {
                    attrs.computeIfAbsent(name, k -> new ArrayList<>()).addAll(values);
                }
            }
        }

        return attrs;
    }

    private Document parseXmlSecure(byte[] xmlBytes) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
            DocumentBuilder db = dbf.newDocumentBuilder();
            return db.parse(new ByteArrayInputStream(xmlBytes));
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML", e);
        }
    }

    private String xpathString(Document doc, String expr) {
        try {
            XPath xPath = XPathFactory.newInstance().newXPath();
            String s = (String) xPath.evaluate(expr, doc, XPathConstants.STRING);
            return StringUtils.hasText(s) ? s.trim() : null;
        } catch (XPathExpressionException e) {
            throw new SamlProcessingException("XPath error: " + expr, e);
        }
    }

    private NodeList xpathNodeList(Document doc, String expr) {
        try {
            XPath xPath = XPathFactory.newInstance().newXPath();
            return (NodeList) xPath.evaluate(expr, doc, XPathConstants.NODESET);
        } catch (XPathExpressionException e) {
            throw new SamlProcessingException("XPath error: " + expr, e);
        }
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String nameId;
    private final Map<String, List<String>> attributes;

    SamlAuthenticationToken(String nameId, Collection<? extends GrantedAuthority> authorities, Map<String, List<String>> attributes) {
        super(authorities);
        this.nameId = nameId;
        this.attributes = attributes != null ? Collections.unmodifiableMap(new LinkedHashMap<>(attributes)) : Map.of();
        setAuthenticated(false);
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public Object getPrincipal() {
        return nameId;
    }

    public String getNameId() {
        return nameId;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }
}

record SamlParsedResponse(
        String issuer,
        String nameId,
        String sessionIndex,
        Long notOnOrAfterEpochSeconds,
        Map<String, List<String>> attributes
) {}

class SamlProcessingException extends RuntimeException {
    SamlProcessingException(String message) {
        super(message);
    }

    SamlProcessingException(String message, Throwable cause) {
        super(message, cause);
    }
}

@Component
class SamlSessionAuthenticationFilter extends org.springframework.web.filter.OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        HttpSession session = request.getSession(false);
        if (session != null && SecurityContextHolder.getContext().getAuthentication() == null) {
            Object ctx = session.getAttribute(HttpSessionSecurityContextRepository.SPRING_SECURITY_CONTEXT_KEY);
            if (ctx instanceof SecurityContext sc && sc.getAuthentication() != null) {
                SecurityContextHolder.setContext(sc);
            }
        }
        filterChain.doFilter(request, response);
    }
}

@RestController
@RequestMapping("/me")
class MeController {

    @GetMapping
    public Map<String, Object> me(HttpServletRequest request, Authentication authentication) {
        HttpSession session = request.getSession(false);
        Map<String, Object> out = new LinkedHashMap<>();
        out.put("authenticated", authentication != null && authentication.isAuthenticated());
        out.put("principal", authentication != null ? authentication.getName() : null);

        if (session != null) {
            Object attrs = session.getAttribute(SamlResponseProcessor.SESSION_SAML_ATTRIBUTES);
            Object nameId = session.getAttribute(SamlResponseProcessor.SESSION_SAML_NAMEID);
            Object issuer = session.getAttribute(SamlResponseProcessor.SESSION_SAML_ISSUER);
            Object sessionIndex = session.getAttribute(SamlResponseProcessor.SESSION_SAML_SESSION_INDEX);
            Object noa = session.getAttribute(SamlResponseProcessor.SESSION_SAML_NOT_ON_OR_AFTER);

            out.put("nameId", nameId);
            out.put("issuer", issuer);
            out.put("sessionIndex", sessionIndex);
            out.put("notOnOrAfterEpochSeconds", noa);
            out.put("attributes", attrs);
        }
        return out;
    }
}

@RestController
@RequestMapping("/saml")
class SamlLoginController {

    @GetMapping("/login")
    public ResponseEntity<Void> login(@RequestParam(value = "returnTo", required = false) String returnTo) {
        String target = "/";
        if (StringUtils.hasText(returnTo)) {
            String rt = returnTo.trim();
            if (rt.startsWith("/")) target = rt;
        }
        String location = "/saml/acs?RelayState=" + URLEncoder.encode(target, StandardCharsets.UTF_8);
        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.LOCATION, location);
        return new ResponseEntity<>(headers, HttpStatus.FOUND);
    }
}